# Unit Tests for `interleave` Function

```python
import pytest


def interleave(a: list, b: list) -> list:
    result = []
    for x, y in zip(a, b):
        result.extend([x, y])
    result.extend(a[len(b):] or b[len(a):])
    return result


class TestInterleaveHappyPath:
    """Test cases for normal, expected behavior."""

    def test_equal_length_lists(self):
        """Test interleaving two lists of equal length."""
        assert interleave([1, 2, 3], [4, 5, 6]) == [1, 4, 2, 5, 3, 6]

    def test_equal_length_lists_strings(self):
        """Test interleaving lists of strings."""
        assert interleave(['a', 'b'], ['x', 'y']) == ['a', 'x', 'b', 'y']

    def test_equal_length_lists_mixed_types(self):
        """Test interleaving lists with mixed types."""
        assert interleave([1, 'a'], [2.5, None]) == [1, 2.5, 'a', None]

    def test_first_list_longer(self):
        """Test when first list is longer than second."""
        assert interleave([1, 2, 3, 4], [5, 6]) == [1, 5, 2, 6, 3, 4]

    def test_second_list_longer(self):
        """Test when second list is longer than first."""
        assert interleave([1, 2], [3, 4, 5, 6]) == [1, 3, 2, 4, 5, 6]

    def test_single_element_lists(self):
        """Test interleaving single-element lists."""
        assert interleave([1], [2]) == [1, 2]

    def test_single_element_first_list_longer(self):
        """Test single element in second list, multiple in first."""
        assert interleave([1, 2, 3], [4]) == [1, 4, 2, 3]

    def test_single_element_second_list_longer(self):
        """Test single element in first list, multiple in second."""
        assert interleave([1], [2, 3, 4]) == [1, 2, 3, 4]


